external_knowledge:
- A user is considered bullish if their overall sentiment trend is positive, indicating a generally positive attitude towards the stocks they have commented on; 
- A user is considered bearish if their overall sentiment trend is negative, indicating a generally negative attitude towards the stocks they have commented on; 
- A user is considered neutral if their overall sentiment trend is zero, indicating a balanced or mixed attitude towards the stocks they have commented on.

sql:
SELECT AVG(sentiment_score) AS avg_sentiment_score
FROM comment_stocks
WHERE stock_id = 0;

SELECT MAX(sentiment_score) AS max_sentiment_score
FROM comment_stocks
WHERE stock_id = (SELECT stock_id FROM stocks WHERE stock_symbol = 'TSLA');

SELECT comment_text, date, AVG(sentiment_confidence) AS average_sentiment_confidence
FROM comments
WHERE comment_id = 1;

SELECT AVG(sa.sentiment_score) AS overall_avg_sentiment_score
FROM sentiment_analysis sa
JOIN comment_stocks cs ON sa.comment_id = cs.comment_id;

SELECT MAX(sentiment_score) AS max_sentiment_score
FROM comment_stocks
WHERE sentiment_category = 'bearish';
